def kmer_seed_match(query, database, k=3, min_hits=2):
    """Find database sequences sharing >= min_hits k-mers with query."""
    query_kmers = set(extract_kmers(query, k))
    hits = []
    for idx, db_seq in enumerate(database):
        db_kmers = set(extract_kmers(db_seq, k))
        shared = {{prot_struct_new_mmseqs_b2}}
        if len(shared) >= min_hits:
            hits.append((idx, len(shared)))
